/* #include "tile_sprites.h" -- merged */
/* #include "sprite.h" -- merged */
/* #include "soldier_frames.h" -- merged */
/**************************************************/
/* DECOR LOOKUP MAP                               */
/* Same dimensions as tile map (15x20)            */
/* Each cell will have up to DECO_CELL_CAP decors */
/* built only ocne during init                    */
/**************************************************/

DecoCell deco_map[MAP_HEIGHT][MAP_WIDTH];

const DecoCell *deco_map_get_cell(int row, int col){
    return &deco_map[row][col];
}

void deco_map_build(void){
    //first cell every cell
    for(int r=0; r < MAP_HEIGHT; r++){
        for (int c = 0; c < MAP_WIDTH; c++){
            deco_map[r][c].count = 0;
        }
    }

    for(int i = 0; i < deco_count; i++){
        const DecoType *d = &DECO_LOOKUP[decorations[i].type];
        //get all the cells it touches
        int c0 = decorations[i].x / TILE_W;
        int r0 = decorations[i].y /TILE_H;
        int c1 = (decorations[i].x + d->w - 1) / TILE_W;
        int r1 = (decorations[i].y + d->h - 1) / TILE_H;

        for(int r = r0; r <= r1 && r < MAP_HEIGHT; r++){
            for(int c = c0; c <= c1 && c < MAP_WIDTH; c++){
                if(r < 0 || c < 0){
                    continue;
                }
                DecoCell *cell = &deco_map[r][c];
                if(cell->count < DECO_CELL_CAP){
                    cell->indices[cell->count++] = (unsigned char)i;
                }
            }
        }
    }
}

/*return 1 is tile is next to water*/
int is_next_to_water(int row, int col){
    const int dr[] = {-1, 1, 0, 0};
    const int dc[] = {0, 0, -1, 1};
    for(int d = 0; d < 4; d++){
        int r = row + dr[d];
        int c = col + dc[d];
        if(r < 0 || r >= MAP_HEIGHT || c < 0 || c >= MAP_WIDTH) continue;
        if(map_get_tile(r, c) == SPRITE_TILE_WATER) return 1;
    }
    return 0;
}

/*return 1 if any decoration already places is a tree in the radius*/
int is_near_tree(int px, int py, int radius){
    for(int i = 0; i < deco_count; i++){
        int dtype = decorations[i].type;
        if (dtype != DECO_TREE_GREEN_A && dtype != DECO_TREE_GREEN_B &&
            dtype !=DECO_AUTUMN_TREE_RED_MED && dtype != DECO_AUTUMN_TREE_RED_SM &&
            dtype != DECO_AUTUMN_TREE_YELLOW_MED && dtype != DECO_AUTUMN_TREE_YELLOW_SM &&
            dtype != DECO_STICK_TREE_MED && dtype != DECO_GREEN_PLANT_TREE_A) continue;
        int dx = decorations[i].x - px;
        int dy = decorations[i].y - py;
        if (dx < 0) dx = -dx;
        if (dy < 0) dy = -dy;
        if (dx < radius && dy < radius) return 1;
    }
    return 0;
}

//spacing check
int too_close_to_any(int px, int py, int min_spacing) {
    for (int i = 0; i < deco_count; i++) {
        const DecoType *other = &DECO_LOOKUP[decorations[i].type];
        int dx = decorations[i].x - px;
        int dy = decorations[i].y - py;
        if (dx < 0) dx = -dx;
        if (dy < 0) dy = -dy;
        if (dx < other->w + min_spacing && dy < other->h + min_spacing) return 1;
    }
    return 0;
}

/*Place one decor*/
int place_deco(int type, int px, int py) {
    if (deco_count >= MAX_DECORATIONS) return 0;
    decorations[deco_count++] = (Decoration){ (short)px, (short)py, (unsigned char)type };
    return 1;
}

void decoration_init(int map_index){
    deco_count = 0;
    
    const MapConfig *cfg = &MAP_CONFIGS[map_index];
    const int MAX_ATTEMPTS = 500;
    const int MIN_SPACING = 0;

    /* ---- Build tree table from config ---- */
    int TREE_TABLE_BIG[12];
    int TREE_TABLE_SMALL[8];
    int TREE_COUNT_BIG = 0;
    int TREE_COUNT_SMALL = 0;

    if(cfg->use_ice_trees != 2 && cfg->use_autumn_trees != 2 && cfg->use_stick_trees != 2){ //if 2 only use ice trees
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_GREEN_TREE_LG;
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_TREE_GREEN_B;     
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_TREE_GREEN_A;
    }
    if (cfg->use_autumn_trees && cfg->use_ice_trees != 2 && cfg->use_stick_trees != 2) {
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_AUTUMN_TREE_RED_LG;
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_AUTUMN_TREE_RED_MED;
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_AUTUMN_TREE_YELLOW_LG;
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_AUTUMN_TREE_YELLOW_MED;
    }
    if (cfg->use_ice_trees && cfg->use_autumn_trees != 2 && cfg->use_stick_trees != 2){
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_ICE_TREE_LG;
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_ICE_TREE_MED;
    }
    if (cfg->use_stick_trees && cfg->use_ice_trees != 2 && cfg->use_autumn_trees != 2){
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_STICK_TREE_B;
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_STICK_TREE_LG;
        TREE_TABLE_BIG[TREE_COUNT_BIG++] = DECO_STICK_TREE_MED;
    }

    if(cfg->use_autumn_trees != 2 && cfg->use_ice_trees != 2 && cfg->use_stick_trees != 2){
        TREE_TABLE_SMALL[TREE_COUNT_SMALL++] = DECO_GREEN_PLANT_TREE_A;
    }
    if (cfg->use_autumn_trees && cfg->use_ice_trees != 2 && cfg->use_stick_trees != 2) {
        TREE_TABLE_SMALL[TREE_COUNT_SMALL++] = DECO_AUTUMN_TREE_RED_SM;
        TREE_TABLE_SMALL[TREE_COUNT_SMALL++] = DECO_AUTUMN_TREE_YELLOW_SM;
    }
    if(cfg->use_ice_trees && cfg->use_autumn_trees != 2 && cfg->use_stick_trees != 2){
        TREE_TABLE_SMALL[TREE_COUNT_SMALL++] = DECO_ICE_TREE_SM;
    }
    if(cfg->use_stick_trees && cfg->use_autumn_trees != 2 && cfg->use_ice_trees != 2){
        TREE_TABLE_SMALL[TREE_COUNT_SMALL++] = DECO_STICK_TREE_SM;
    }

    /* ---- Build rock table ---- */
    int ROCK_TABLE_BIG[4];
    int ROCK_TABLE_SMALL[6];
    int ROCK_COUNT_BIG = 0;
    int ROCK_COUNT_SMALL = 0;

    if (cfg->use_grey_rocks != 1) {
        ROCK_TABLE_BIG[ROCK_COUNT_BIG++]     = DECO_ROCK_BIG_BROWN;
        ROCK_TABLE_BIG[ROCK_COUNT_BIG++]     = DECO_ROCK_MED_BROWN;
        ROCK_TABLE_SMALL[ROCK_COUNT_SMALL++] = DECO_ROCK_SM_A_BROWN;
        ROCK_TABLE_SMALL[ROCK_COUNT_SMALL++] = DECO_ROCK_SM_B_BROWN;
        ROCK_TABLE_SMALL[ROCK_COUNT_SMALL++] = DECO_ROCK_SM_C_BROWN;
    }
    if (cfg->use_grey_rocks >= 1) {
        ROCK_TABLE_BIG[ROCK_COUNT_BIG++]     = DECO_ROCK_BIG_GREY;
        ROCK_TABLE_BIG[ROCK_COUNT_BIG++]     = DECO_ROCK_MED_GREY;
        ROCK_TABLE_SMALL[ROCK_COUNT_SMALL++] = DECO_ROCK_SM_A_GREY;
        ROCK_TABLE_SMALL[ROCK_COUNT_SMALL++] = DECO_ROCK_SM_B_GREY;
        ROCK_TABLE_SMALL[ROCK_COUNT_SMALL++] = DECO_ROCK_SM_C_GREY;
    }

    const int BUSH_TABLE[] = {
        DECO_BUSH_GREEN_SM, DECO_BUSH_OLIVE_SM, DECO_BUSH_RED_SM,
        DECO_BUSH_GREEN_LG, DECO_BUSH_OLIVE_LG,
    };
    const int BUSH_COUNT = 5;

    const int SMALL_TABLE[] = {
        DECO_ROCK_SM_A_BROWN, DECO_ROCK_SM_B_BROWN, DECO_ROCK_SM_C_BROWN,
        DECO_ROCK_SM_A_GREY,  DECO_ROCK_SM_B_GREY,  DECO_ROCK_SM_C_GREY,
        DECO_FLOWER_PURPLE,
    };
    const int SMALL_COUNT = 7;

    const int CATTAIL_TABLE[] = {
        DECO_CATTAIL_GREEN_LG, DECO_CATTAIL_GREEN_MED, DECO_CATTAIL_GREEN_SM,
    };
    const int CATTAIL_COUNT = 3;

    const int FERN_TABLE[] = {
        DECO_FERN_GREEN_LG, DECO_FERN_GREEN_MED,
    };
    const int FERN_COUNT = 2;

    /* Build a list of all valid tiles for trees */
    int grass_tiles[MAP_HEIGHT * MAP_WIDTH][2];  /* [i][0] = row, [i][1] = col */
    int grass_count = 0;

    for (int r = 0; r < MAP_HEIGHT; r++) {
        for (int c = 0; c < MAP_WIDTH; c++) {
            SpriteID t = map_get_tile(r, c);
            if (t == SPRITE_TILE_GRASS)
                grass_tiles[grass_count][0] = r,
                grass_tiles[grass_count][1] = c,
                grass_count++;
        }
    }

    /* ---- 1. Place trees (with optional clustering) ---- */
    int trees_placed = 0;
    for (int attempts = 0; attempts < MAX_ATTEMPTS && trees_placed < cfg->tree_budget; attempts++) {
        if (grass_count == 0) break;

        int idx = rand() % grass_count;
        int row = grass_tiles[idx][0];
        int col = grass_tiles[idx][1];

        int type;
        if (cfg->prefer_big_trees == 2) {
            /* big only */
            type = TREE_TABLE_BIG[rand() % TREE_COUNT_BIG];
        } else if (cfg->prefer_big_trees == 1) {
            /* big 75% of the time */
            type = (rand() % 4 != 0)
                ? TREE_TABLE_BIG[rand() % TREE_COUNT_BIG]
                : TREE_TABLE_SMALL[rand() % TREE_COUNT_SMALL];
        } else {
            /* mixed â€” equal chance */
            int all_count = TREE_COUNT_BIG + TREE_COUNT_SMALL;
            int pick = rand() % all_count;
            type = (pick < TREE_COUNT_BIG)
                ? TREE_TABLE_BIG[pick]
                : TREE_TABLE_SMALL[pick - TREE_COUNT_BIG];
        }

        const DecoType *info = &DECO_LOOKUP[type];
        
        int px = col * TILE_W + (rand() % TILE_W);
        int py = row * TILE_H + (rand() % (TILE_H / 2));

        int bot_col = (px + info->w / 2) >> 4;
        int bot_row = (py + info->h - 1) >> 4;
        if (bot_col >= 0 && bot_col < MAP_WIDTH && bot_row >= 0 && bot_row < MAP_HEIGHT) {
            if (map_get_tile(bot_row, bot_col) != SPRITE_TILE_GRASS) continue;
        }
        if (too_close_to_any(px, py, MIN_SPACING)) continue;
        if (!place_deco(type, px, py)) break;
        trees_placed++;

        int cluster_members = cfg->tree_cluster_size - 1;
        for (int ci = 0; ci < cluster_members; ci++) {
            if (trees_placed >= cfg->tree_budget) break;
            int cpx = px + (rand() % 80) - 40;
            int cpy = py + (rand() % 64) - 32;

            int ctype;
            if (cfg->prefer_big_trees == 2) {
                ctype = TREE_TABLE_BIG[rand() % TREE_COUNT_BIG];
            } else if (cfg->prefer_big_trees == 1) {
                ctype = (rand() % 4 != 0)
                    ? TREE_TABLE_BIG[rand() % TREE_COUNT_BIG]
                    : TREE_TABLE_SMALL[rand() % TREE_COUNT_SMALL];
            } else {
                int all_count = TREE_COUNT_BIG + TREE_COUNT_SMALL;
                int pick = rand() % all_count;
                ctype = (pick < TREE_COUNT_BIG)
                    ? TREE_TABLE_BIG[pick]
                    : TREE_TABLE_SMALL[pick - TREE_COUNT_BIG];
            }
            const DecoType *ci_info = &DECO_LOOKUP[ctype];

            if (cpy + ci_info->h <= 0 || cpy >= SCREEN_HEIGHT) continue;
            if (cpx + ci_info->w <= 0 || cpx >= SCREEN_WIDTH)  continue;

            int cbot_col = (cpx + ci_info->w / 2) >> 4;
            int cbot_row = (cpy + ci_info->h - 1) >> 4;

            if (cbot_col >= 0 && cbot_col < MAP_WIDTH && cbot_row >= 0 && cbot_row < MAP_HEIGHT) {
                if (map_get_tile(cbot_row, cbot_col) != SPRITE_TILE_GRASS) continue;
            }
            if (too_close_to_any(cpx, cpy, 4)) continue;
            if (place_deco(ctype, cpx, cpy)) trees_placed++;
        }
    }

    /* ---- 2. Place rocks (with optional clustering) ---- */
    int rocks_placed = 0;
    for (int attempts = 0; attempts < MAX_ATTEMPTS && rocks_placed < cfg->rock_budget; attempts++) {
        //get random row and col
        int row = 1 + (rand() % (MAP_HEIGHT - 2));
        int col = 1 + (rand() % (MAP_WIDTH  - 2));
        SpriteID temp = map_get_tile(row, col);
        if (temp != SPRITE_TILE_GRASS && temp != SPRITE_TILE_STONE) continue;

        //give random offset
        int type;
        if (cfg->prefer_big_rocks == 2) {
            type = ROCK_TABLE_BIG[rand() % ROCK_COUNT_BIG];
        } else if (cfg->prefer_big_rocks == 1) {
            type = (rand() % 4 != 0)
                ? ROCK_TABLE_BIG[rand() % ROCK_COUNT_BIG]
                : ROCK_TABLE_SMALL[rand() % ROCK_COUNT_SMALL];
        } else {
            int all_count = ROCK_COUNT_BIG + ROCK_COUNT_SMALL;
            int pick = rand() % all_count;
            type = (pick < ROCK_COUNT_BIG)
                ? ROCK_TABLE_BIG[pick]
                : ROCK_TABLE_SMALL[pick - ROCK_COUNT_BIG];
        }
        const DecoType *info = &DECO_LOOKUP[type];
        int px = col * TILE_W + (rand() % TILE_W);
        int py = row * TILE_H + (rand() % TILE_H);

        //check bottom of rock
        int bot_col = (px + info->w / 2) >> 4;
        int bot_row = (py + info->h - 1) >> 4;
        if (bot_row < 0 || bot_row >= MAP_HEIGHT || bot_col < 0 || bot_col >= MAP_WIDTH) continue;

        temp = map_get_tile(bot_row, bot_col);
        if (temp != SPRITE_TILE_GRASS && temp != SPRITE_TILE_STONE && temp != SPRITE_TILE_DIRT) continue;
        if (too_close_to_any(px, py, MIN_SPACING)) continue;

        //place rock
        if (!place_deco(type, px, py)) break;
        rocks_placed++;

        //this is for clusters
        for (int ci = 1; ci < cfg->rock_cluster_size; ci++) {
            if (rocks_placed >= cfg->rock_budget) break;
            int cpx = px + (rand() % 24) - 12;
            int cpy = py + (rand() % 16) - 8;

            /* Cluster members are smaller rocks */
            int small_rocks[] = {
                DECO_ROCK_SM_A_BROWN, DECO_ROCK_SM_B_BROWN, DECO_ROCK_SM_C_BROWN,
                DECO_ROCK_SM_A_GREY,  DECO_ROCK_SM_B_GREY,  DECO_ROCK_SM_C_GREY,
            };
            int ctype = small_rocks[(rand() % (cfg->use_grey_rocks >= 1 ? 6 : 3))];
            const DecoType *ci_info = &DECO_LOOKUP[ctype];

            if (cpy + ci_info->h <= 0 || cpy >= SCREEN_HEIGHT) continue;
            if (cpx + ci_info->w <= 0 || cpx >= SCREEN_WIDTH)  continue;

            int cbot_col = (cpx + ci_info->w / 2) >> 4;
            int cbot_row = (cpy + ci_info->h - 1) >> 4;

            if (cbot_row < 0 || cbot_row >= MAP_HEIGHT || cbot_col < 0 || cbot_col >= MAP_WIDTH) continue;
            temp = map_get_tile(cbot_row, cbot_col);
            if (temp != SPRITE_TILE_GRASS && temp != SPRITE_TILE_DIRT && temp && SPRITE_TILE_STONE) continue;
            if (too_close_to_any(cpx, cpy, 3)) continue;
            if (place_deco(ctype, cpx, cpy)) rocks_placed++;
        }
    }

    /* ---- 3. Place bushes ---- */
    int bushes_placed = 0;
    for (int attempts = 0; attempts < MAX_ATTEMPTS && bushes_placed < cfg->bush_budget; attempts++) {
        int row = 1 + (rand() % (MAP_HEIGHT - 2));
        int col = 1 + (rand() % (MAP_WIDTH  - 2));
        if (map_get_tile(row, col) != SPRITE_TILE_GRASS) continue;

        int type = BUSH_TABLE[rand() % BUSH_COUNT];
        const DecoType *info = &DECO_LOOKUP[type];
        int px = col * TILE_W + (rand() % TILE_W);
        int py = row * TILE_H + (rand() % (TILE_H / 2));

        int bot_col = (px + info->w / 2) >> 4;
        int bot_row = (py + info->h - 1) >> 4;

        if (bot_row < 0 || bot_row >= MAP_HEIGHT || bot_col < 0 || bot_col >= MAP_WIDTH) continue;
        if (map_get_tile(bot_row, bot_col) != SPRITE_TILE_GRASS) continue;
        if (too_close_to_any(px, py, MIN_SPACING)) continue;
        if (place_deco(type, px, py)) bushes_placed++;
    }

    /* ---- 4. Place small props ---- */
    int smalls_placed = 0;
    for (int attempts = 0; attempts < MAX_ATTEMPTS && smalls_placed < cfg->small_budget; attempts++) {
        int row = 1 + (rand() % (MAP_HEIGHT - 2));
        int col = 1 + (rand() % (MAP_WIDTH  - 2));
        if (map_get_tile(row, col) != SPRITE_TILE_GRASS) continue;

        int type = SMALL_TABLE[rand() % SMALL_COUNT];
        const DecoType *info = &DECO_LOOKUP[type];
        int px = col * TILE_W + (rand() % TILE_W);
        int py = row * TILE_H + (rand() % TILE_H);
        int bot_col = (px + info->w / 2) >> 4;
        int bot_row = (py + info->h - 1) >> 4;

        if (bot_row < 0 || bot_row >= MAP_HEIGHT || bot_col < 0 || bot_col >= MAP_WIDTH) continue;
        if (map_get_tile(bot_row, bot_col) != SPRITE_TILE_GRASS) continue;
        if (too_close_to_any(px, py, 6)) continue;
        if (place_deco(type, px, py)) smalls_placed++;
    }

    /* ---- 5. Place cattails â€” grass tiles adjacent to water only ---- */
    int cattails_placed = 0;
    for (int attempts = 0; attempts < MAX_ATTEMPTS && cattails_placed < cfg->cattail_budget; attempts++) {
        int row = 1 + (rand() % (MAP_HEIGHT - 2));
        int col = 1 + (rand() % (MAP_WIDTH  - 2));
        if (map_get_tile(row, col) != SPRITE_TILE_GRASS) continue;
        if (!is_next_to_water(row, col)) continue;  /* <-- the key filter */

        int type = CATTAIL_TABLE[rand() % CATTAIL_COUNT];
        const DecoType *info = &DECO_LOOKUP[type];
        int px = col * TILE_W + (rand() % TILE_W);
        int py = row * TILE_H + (rand() % (TILE_H / 2));

        int bot_col = (px + info->w / 2) >> 4;
        int bot_row = (py + info->h - 1) >> 4;

        if (bot_row < 0 || bot_row >= MAP_HEIGHT || bot_col < 0 || bot_col >= MAP_WIDTH) continue;
        if (map_get_tile(bot_row, bot_col) != SPRITE_TILE_GRASS) continue;
        if (too_close_to_any(px, py, 4)) continue;  /* cattails can be fairly close together */
        if (place_deco(type, px, py)) cattails_placed++;
    }

    /* ---- 6. Place ferns â€” grass tiles near already-placed trees only ---- */
    int ferns_placed = 0;
    for (int attempts = 0; attempts < MAX_ATTEMPTS && ferns_placed < cfg->fern_budget; attempts++) {
        int row = 1 + (rand() % (MAP_HEIGHT - 2));
        int col = 1 + (rand() % (MAP_WIDTH  - 2));
        if (map_get_tile(row, col) != SPRITE_TILE_GRASS) continue;

        int px = col * TILE_W + (rand() % TILE_W);
        int py = row * TILE_H + (rand() % TILE_H);
        if (!is_near_tree(px, py, 32)) continue;  /* within ~2 tiles of a tree */

        int type = FERN_TABLE[rand() % FERN_COUNT];
        const DecoType *info = &DECO_LOOKUP[type];
        int bot_col = (px + info->w / 2) >> 4;
        int bot_row = (py + info->h - 1) >> 4;

        if (bot_row < 0 || bot_row >= MAP_HEIGHT || bot_col < 0 || bot_col >= MAP_WIDTH) continue;
        if (map_get_tile(bot_row, bot_col) != SPRITE_TILE_GRASS) continue;
        if (too_close_to_any(px, py, 5)) continue;
        if (place_deco(type, px, py)) ferns_placed++;
    }

    canopy_count = 0;
    for (int i = 0; i < deco_count; i++) {
        if (deco_has_canopy(decorations[i].type))
            canopy_indices[canopy_count++] = i;
    }

    deco_map_build();
}

void decoration_draw_all(void){
    for(int i = 0; i < deco_count; i++){
        const DecoType *d = &DECO_LOOKUP[decorations[i].type];
        Sprite s = {
            d->w,
            d->h,
            d->data
        };
        draw_sprite(&s, decorations[i].x, decorations[i].y, 0, 0);
    }
}

//need to redraw decor if a sprite overlaps it
void decoration_redraw_region(int row0, int col0, int row1, int col1) {
    int clip_x0 = col0 * TILE_W;
    int clip_x1 = col1 * TILE_W - 1;
    int clip_y0 = row0 * TILE_H;
    int clip_y1 = row1 * TILE_H - 1;

    for (int i = 0; i < deco_count; i++) {
        const DecoType *d = &DECO_LOOKUP[decorations[i].type];
        int sx = decorations[i].x;
        int sy = decorations[i].y;

        /* Broad phase â€” skip entirely if no overlap */
        if (sx + d->w <= clip_x0 || sx > clip_x1) continue;
        if (sy + d->h <= clip_y0 || sy > clip_y1) continue;

        /* Tight row bounds â€” only iterate rows inside the clip rect */
        int row_start = clip_y0 - sy;
        int row_end   = clip_y1 - sy + 1;
        if (row_start < 0) row_start = 0;
        if (row_end > d->h) row_end = d->h;

        /* Tight col bounds */
        int col_start = clip_x0 - sx;
        int col_end   = clip_x1 - sx + 1;
        if (col_start < 0) col_start = 0;
        if (col_end > d->w) col_end = d->w;

        for (int row = row_start; row < row_end; row++) {
            int py = sy + row;
            if (py < 0 || py >= SCREEN_HEIGHT) continue;
            for (int col = col_start; col < col_end; col++) {
                int px = sx + col;
                if (px < 0 || px >= SCREEN_WIDTH) continue;
                short colour = d->data[row * d->w + col];
                if ((unsigned short)colour != (unsigned short)TRANSPARENT)
                    plot_pixel(px, py, colour);
            }
        }
    }
}

/* Which types have a tall canopy that should draw over players */
int deco_has_canopy(int deco_type) {
    switch (deco_type) {
        case DECO_TREE_GREEN_A:
        case DECO_TREE_GREEN_B:
        case DECO_GREEN_TREE_LG:

        case DECO_AUTUMN_TREE_RED_LG:
        case DECO_AUTUMN_TREE_RED_MED:
        case DECO_AUTUMN_TREE_YELLOW_LG:
        case DECO_AUTUMN_TREE_YELLOW_MED:

        case DECO_STICK_TREE_B:
        case DECO_STICK_TREE_LG:
        case DECO_STICK_TREE_MED:

        case DECO_ICE_TREE_LG:
        case DECO_ICE_TREE_MED:

        case DECO_ROCK_BIG_GREY:
        case DECO_ROCK_BIG_BROWN:
        case DECO_ROCK_MED_BROWN:
        case DECO_ROCK_MED_GREY:
            return 1;
        default:
            return 0;
    }
}

void decoration_draw_canopies_near(int px1, int py1, int px2, int py2) {
    for (int i = 0; i < canopy_count; i++) {
        const Decoration *d = &decorations[canopy_indices[i]];
        const DecoType *dt = &DECO_LOOKUP[d->type];
        int sx = d->x;
        int sy = d->y;

        /* Only redraw canopy if a player overlaps this decoration's x range */
        int near = 0;
        if (px1 >= sx - SOLDIER_H && px1 <= sx + dt->w) near = 1;
        if (px2 >= sx - SOLDIER_W && px2 <= sx + dt->w) near = 1;
        if (!near) continue;

        int cutoff_py = sy + dt->h - 6;
        for (int row = 0; row < dt->h; row++) {
            int py = sy + row;
            if (py >= cutoff_py) break;
            if (py < 0 || py >= SCREEN_HEIGHT) continue;
            for (int col = 0; col < dt->w; col++) {
                int ppx = sx + col;
                if (ppx < 0 || ppx >= SCREEN_WIDTH) continue;
                short colour = dt->data[row * dt->w + col];
                if ((unsigned short)colour != (unsigned short)TRANSPARENT)
                    plot_pixel(ppx, py, colour);
            }
        }
    }
}

void deco_canopy_rebuild(void){
    canopy_count = 0;
    for (int i = 0; i < deco_count; i++){
        if (deco_has_canopy(decorations[i].type))
            canopy_indices[canopy_count++] = i;
    }
}


/* ===========================================================================
 * src/game/obstacle_map.c
 * =========================================================================*/
/* #include "obstacle_map.h" -- merged */
/* #include "map.h" -- merged */
/* #include "decorations.h" -- merged */
/* #include "sprite.h" -- merged */
/* #include "tile_sprites.h" -- merged */

unsigned char obstacle_map[MAP_HEIGHT][MAP_WIDTH];

/* Which decoration types block movement / projectiles */
int deco_is_solid(int deco_type) {
    switch (deco_type) {
        case DECO_ROCK_BIG_BROWN:
        case DECO_ROCK_BIG_GREY:
        case DECO_ROCK_MED_BROWN:
        case DECO_ROCK_MED_GREY:

        case DECO_TREE_GREEN_A:
        case DECO_TREE_GREEN_B:
        case DECO_GREEN_TREE_LG:

        case DECO_AUTUMN_TREE_RED_LG:
        case DECO_AUTUMN_TREE_RED_MED:
        case DECO_AUTUMN_TREE_YELLOW_LG:
        case DECO_AUTUMN_TREE_YELLOW_MED:

        case DECO_STICK_TREE_B:
        case DECO_STICK_TREE_LG:
        case DECO_STICK_TREE_MED:

        case DECO_ICE_TREE_LG:
        case DECO_ICE_TREE_MED:
            return 1;
        default:
            return 0;
    }
}

void obstacle_map_init(void) {
    /* 1. Clear everything */
    for (int r = 0; r < MAP_HEIGHT; r++)
        for (int c = 0; c < MAP_WIDTH; c++)
            obstacle_map[r][c] = 0;

    /* 2. Stamp tile-based flags (water = slow + no projectiles) */
    for (int r = 0; r < MAP_HEIGHT; r++) {
        for (int c = 0; c < MAP_WIDTH; c++) {
            SpriteID tile = map_get_tile(r, c);
            if (tile == SPRITE_TILE_WATER) {
                obstacle_map[r][c] |= TILE_FLAG_SLOW;
            }
        }
    }

    /* 3. Stamp decoration-based flags â€” bottom row only for SOLID */
    for (int i = 0; i < deco_count; i++) {
        const Decoration *d   = &decorations[i];
        const DecoType   *dt  = &DECO_LOOKUP[d->type];

        /* Bottom row only â€” player walks "behind" the upper part */
        int base_row  = (d->y + dt->h - 1) / TILE_H;
        int col_left  = d->x / TILE_W;
        int col_right = (d->x + dt->w - 1) / TILE_W;

        if (deco_is_solid(d->type)) {
            for (int c = col_left; c <= col_right; c++)
                obstacle_map_set(base_row, c, TILE_FLAG_SOLID);
        }
    }
}

void obstacle_map_set(int row, int col, unsigned char flags) {
    if (row < 0 || row >= MAP_HEIGHT || col < 0 || col >= MAP_WIDTH) return;
    obstacle_map[row][col] |= flags;
}

void obstacle_map_clear(int row, int col, unsigned char flags) {
    if (row < 0 || row >= MAP_HEIGHT || col < 0 || col >= MAP_WIDTH) return;
    obstacle_map[row][col] &= ~flags;
}

unsigned char obstacle_map_get(int row, int col) {
    if (row < 0 || row >= MAP_HEIGHT || col < 0 || col >= MAP_WIDTH) return 0;
    return obstacle_map[row][col];
}

int pixel_to_col(int px) { return px / TILE_W; }
int pixel_to_row(int py) { return py / TILE_H; }

unsigned char obstacle_map_at_pixel(int px, int py) {
    return obstacle_map_get(pixel_to_row(py), pixel_to_col(px));
}


/* ===========================================================================
 * src/game/map_evolution.c
 * =========================================================================*/
/* #include "map_evolution.h" -- merged */

/* #include "map.h" -- merged */
/* #include "decorations.h" -- merged */
/* #include "obstacle_map.h" -- merged */
/* #include "tile_sprites.h" -- merged */
/* #include "renderer.h" -- merged */
/* #include "vga.h" -- merged */


/* Part 1: Dirty tile queue*/
//remember there is a double buffer

TileRedraw tile_redraws[TILE_REDRAW_CAP];
int tile_redraw_count = 0;

//add tile to pending redraw list
void tile_redraw_enqueue (int row, int col){
    //if already queue, make sure both buffers are marked
    for(int i = 0; i < tile_redraw_count; i++){
        if(tile_redraws[i].row == row && tile_redraws[i].col == col){
            tile_redraws[i].draw_b0 = 1;
            tile_redraws[i].draw_b1 = 1;
            return;
        }
    }
    if(tile_redraw_count >= TILE_REDRAW_CAP) return;

    tile_redraws[tile_redraw_count].row = (short) row;
    tile_redraws[tile_redraw_count].col = (short) col;
    tile_redraws[tile_redraw_count].draw_b0 = 1;
    tile_redraws[tile_redraw_count].draw_b1 = 1;
    tile_redraw_count++;
}

//pending deco type-change redraws

int deco_redraw_count = 0;

void deco_redraw_enqueue(int idx){
    const DecoType *old_dt = &DECO_LOOKUP[decorations[idx].type];
    short ec0 = (short) (decorations[idx].x >> 4);
    short er0 = (short) (decorations[idx].y >> 4);
    short ec1 = (short) (((decorations[idx].x + old_dt->w - 1) >> 4) + 1);
    short er1 = (short) (((decorations[idx].y + old_dt->h - 1) >> 4) + 1);

    for (int i = 0; i < deco_redraw_count; i++){
        if (deco_redraws[i].deco_idx == idx){
            /* Already queued â€” expand erase box to union with previous old box */
            if (ec0 < deco_redraws[i].erase_col0) deco_redraws[i].erase_col0 = ec0;
            if (er0 < deco_redraws[i].erase_row0) deco_redraws[i].erase_row0 = er0;
            if (ec1 > deco_redraws[i].erase_col1) deco_redraws[i].erase_col1 = ec1;
            if (er1 > deco_redraws[i].erase_row1) deco_redraws[i].erase_row1 = er1;
            deco_redraws[i].draw_b0 = 1;
            deco_redraws[i].draw_b1 = 1;
            return;
        }
    }
    if(deco_redraw_count >= DECO_REDRAW_CAP) return;
    
    deco_redraws[deco_redraw_count].deco_idx   = idx;
    deco_redraws[deco_redraw_count].draw_b0    = 1;
    deco_redraws[deco_redraw_count].draw_b1    = 1;
    deco_redraws[deco_redraw_count].erase_col0 = ec0;
    deco_redraws[deco_redraw_count].erase_row0 = er0;
    deco_redraws[deco_redraw_count].erase_col1 = ec1;
    deco_redraws[deco_redraw_count].erase_row1 = er1;
    deco_redraw_count++;
}


/* Map Evolution Draw */

void map_evolution_draw(int cur_buf){
    //tile redraws

    int new_count = 0;
    for(int i = 0; i < tile_redraw_count; i++){
        TileRedraw *tr = &tile_redraws[i];

        if((cur_buf == 0 && tr->draw_b0) || (cur_buf == 1 && tr->draw_b1)){
            int r = tr->row;
            int c = tr->col;
            SpriteID id = map_get_tile(r,c);

            //repaint the tile itself
            draw_sprite(&sprites[id], c << 4, r << 4, 0, 0);

            //repaint decoration
            decoration_redraw_region(r, c, r + 1, c + 1);

            if(cur_buf == 0) tr->draw_b0 = 0;
            else tr->draw_b1 = 0;
        }

        if(tr->draw_b0 || tr->draw_b1)
            tile_redraws[new_count++] = *tr;
    }
    tile_redraw_count = new_count;

    //deco type-chane redraw
    new_count = 0;
    for(int i = 0; i < deco_redraw_count; i++){
        DecoRedraw *dr = &deco_redraws[i];

        if((cur_buf == 0 && dr->draw_b0) || (cur_buf == 1 && dr->draw_b1)){
            int idx = dr->deco_idx;

            //need to erase using old bounding box
            for(int rr = dr->erase_row0; rr < dr->erase_row1 && rr < MAP_HEIGHT; rr++){
                for(int cc = dr->erase_col0; cc < dr->erase_col1 && cc < MAP_WIDTH; cc++){
                     draw_sprite(&sprites[map_get_tile(rr, cc)], cc << 4, rr << 4, 0, 0);
                }
            }

            //now draw new sprite
            const DecoType *dt = &DECO_LOOKUP[decorations[idx].type];

            //now we can draw the decoration
            Sprite s = { dt->w, dt->h, dt->data};
            draw_sprite(&s, decorations[idx].x, decorations[idx].y, 0, 0);

            if(cur_buf == 0) 
                dr->draw_b0 = 0;
            else 
                dr->draw_b1 = 0;
        }

        if(dr->draw_b0 || dr->draw_b1)
            deco_redraws[new_count++] = *dr;
    }
    deco_redraw_count = new_count;
}

/* Now helpers for all the map evolutions type*/

void map_change_tile (int row, int col, SpriteID new_id, unsigned char new_flags){
    if(row < 0 || row >= MAP_HEIGHT || col < 0 || col >= MAP_WIDTH) return;

    SpriteID old_id = map_get_tile(row, col);
    if(old_id == new_id) return;

    map_set_tile(row, col, new_id);

    //update obstacle flags
    if (old_id == SPRITE_TILE_WATER)
        obstacle_map_clear(row, col, TILE_FLAG_SLOW);
    if(old_id == SPRITE_TILE_LAVA)
        obstacle_map_clear(row, col, TILE_FLAG_DAMAGE);

    if(new_flags)
        obstacle_map_set(row, col, new_flags);

    tile_redraw_enqueue(row, col);
}

/*deco type change */

void deco_change_type(int idx, int new_type){
    if (idx < 0 || idx >= deco_count) return;

    int old_type = decorations[idx].type;
    if(old_type == new_type) return;

    const DecoType *old_dt = &DECO_LOOKUP[old_type];
    const DecoType *new_dt = &DECO_LOOKUP[new_type];

    //obstacle map, remove old solid footprint
    if(deco_is_solid(old_type)){
        int base_row = (decorations[idx].y + old_dt->h - 1) >> 4;
        int cl = decorations[idx].x >> 4;
        int cr = (decorations[idx].x + old_dt->w - 1) >> 4;

        for(int c = cl; c <= cr; c++)
            obstacle_map_clear(base_row, c, TILE_FLAG_SOLID);
    }

    //apply new type now
    decorations[idx].type = new_type;

    /* now stamp new flags into obstacle map*/
    if(deco_is_solid(new_type)){
        int base_row = (decorations[idx].y + new_dt->h - 1) >> 4;
        int cl       =  decorations[idx].x >> 4;
        int cr       = (decorations[idx].x + new_dt->w - 1) >> 4;
        for (int c = cl; c <= cr; c++)
            obstacle_map_set(base_row, c, TILE_FLAG_SOLID);
    }

    //need to rebuld canopy list
    deco_canopy_rebuild();

    deco_redraw_enqueue(idx);
}


/* burn table, what each deco maps to when it burns */

int deco_burn_target(int type){
    switch(type){
        case DECO_GREEN_TREE_LG:    return DECO_STICK_TREE_LG;
        case DECO_AUTUMN_TREE_RED_LG:       return DECO_STICK_TREE_LG;
        case DECO_AUTUMN_TREE_YELLOW_LG:    return DECO_STICK_TREE_LG;
        case DECO_TREE_GREEN_B:             return DECO_STICK_TREE_B;
        case DECO_TREE_GREEN_A:             return DECO_STICK_TREE_MED;
        case DECO_AUTUMN_TREE_RED_MED:      return DECO_STICK_TREE_MED;
        case DECO_AUTUMN_TREE_YELLOW_MED:   return DECO_STICK_TREE_MED;
        case DECO_GREEN_PLANT_TREE_A:       return DECO_STICK_TREE_SM;
        case DECO_AUTUMN_TREE_RED_SM:       return DECO_STICK_TREE_SM;
        case DECO_AUTUMN_TREE_YELLOW_SM:    return DECO_STICK_TREE_SM;
        default: return -1;
    }
}

/* frozen table, what each deco maps to when it freezes*/
int deco_ice_target(int type){
    switch (type) {
        case DECO_GREEN_TREE_LG:            return DECO_ICE_TREE_LG;
        case DECO_AUTUMN_TREE_RED_LG:       return DECO_ICE_TREE_LG;
        case DECO_AUTUMN_TREE_YELLOW_LG:    return DECO_ICE_TREE_LG;
        case DECO_TREE_GREEN_B:             return DECO_ICE_TREE_MED; /* no ice B variant */
        case DECO_TREE_GREEN_A:             return DECO_ICE_TREE_MED;
        case DECO_AUTUMN_TREE_RED_MED:      return DECO_ICE_TREE_MED;
        case DECO_AUTUMN_TREE_YELLOW_MED:   return DECO_ICE_TREE_MED;
        case DECO_GREEN_PLANT_TREE_A:       return DECO_ICE_TREE_SM;
        case DECO_AUTUMN_TREE_RED_SM:       return DECO_ICE_TREE_SM;
        case DECO_AUTUMN_TREE_YELLOW_SM:    return DECO_ICE_TREE_SM;
        default: return -1;
        }
}


/* Per-Map evolution State */

#define MAP_EVO_NONE 0
/* #define MAP_EVO_NONE -- duplicate removed */
#define MAP_EVO_WETLAND 1   /* lava creep + trees burn */
#define MAP_EVO_BEACH   2   /* water -> ice            */
#define MAP_EVO_ICE     3   /* lava appears randomly   */
#define MAP_EVO_ROCKY   4   /* flooding                */

int current_map_evo = MAP_EVO_NONE;
 
/* Shared timers â€” reset on map_evolution_init */
#define EVO_TILE_INTERVAL  90   /* ~1.5 s between each tile change */
#define EVO_DECO_INTERVAL  120  /* ~2 s between each deco change   */

int evo_tile_timer = 0;
int evo_deco_timer = 0;

/* WETLAND map evolution*/

//lava spreads cell-automation style, trees next to lava burn

#define LAVA_MAX 60
typedef struct{
    short row, col;
} LavaCell;

LavaCell lava_cells[LAVA_MAX];
int lava_count = 0;

#define BURN_QUEUE_MAX 20
typedef struct { 
    int deco_idx; 
    int burn_delay; 
} BurnEntry;

BurnEntry burn_queue[BURN_QUEUE_MAX];
int burn_queue_count = 0;
 
void wetland_seed_lava(void) {
    int seeds = 1 + (rand() % 3);
    for (int s = 0; s < seeds && lava_count < LAVA_MAX; s++) {
        for (int attempt = 0; attempt < 200; attempt++) {
            int r = 2 + rand() % (MAP_HEIGHT - 4);
            int c = 2 + rand() % (MAP_WIDTH  - 4);
            SpriteID t = map_get_tile(r, c);
            if (t != SPRITE_TILE_GRASS && t != SPRITE_TILE_DIRT) continue;
            map_change_tile(r, c, SPRITE_TILE_LAVA, TILE_FLAG_DAMAGE);
            lava_cells[lava_count].row = (short)r;
            lava_cells[lava_count].col = (short)c;
            lava_count++;
            break;
        }
    }
}
 
void queue_nearby_tree_burns(int lava_row, int lava_col) {
    for (int i = 0; i < deco_count; i++) {
        if(deco_burn_target(decorations[i].type) == -1) continue;
 
        int already = 0;
        for (int q = 0; q < burn_queue_count; q++)
            if (burn_queue[q].deco_idx == i) { already = 1; break; }
        if (already) continue;
        
        int dtype = decorations[i].type;
        int deco_col = (decorations[i].x + DECO_LOOKUP[dtype].w / 2) >> 4;
        int deco_row = (decorations[i].y + DECO_LOOKUP[dtype].h - 1) >> 4;

        int dist_r   = deco_row - lava_row; 
        if (dist_r < 0) 
            dist_r = -dist_r;

        int dist_c   = deco_col - lava_col; 
        if (dist_c < 0) 
            dist_c = -dist_c;

        if (dist_r > 2 || dist_c > 2) continue;
 
        if (burn_queue_count >= BURN_QUEUE_MAX) return;
        burn_queue[burn_queue_count].deco_idx   = i;
        burn_queue[burn_queue_count].burn_delay = 180 + rand() % 300;
        burn_queue_count++;
    }
}
 
void wetland_update(void) {
    /* Tile tick: spread lava */
    evo_tile_timer++;
    if (evo_tile_timer >= EVO_TILE_INTERVAL && lava_count < LAVA_MAX) {
        evo_tile_timer = 0;
 
        int src = rand() % lava_count;
        int sr  = lava_cells[src].row;
        int sc  = lava_cells[src].col;
 
        int dr[4] = {-1, 1, 0, 0};
        int dc[4] = { 0, 0,-1, 1};
        for (int i = 3; i > 0; i--) {  
            int j = rand() % (i + 1);
            int tmp; 

            tmp = dr[i]; 
            dr[i] = dr[j]; 
            dr[j] = tmp;  

            tmp = dc[i]; 
            dc[i] = dc[j]; 
            dc[j] = tmp;
        }
 
        for (int d = 0; d < 4; d++) {
            int nr = sr + dr[d];
            int nc = sc + dc[d];
            SpriteID t = map_get_tile(nr, nc);
            if (t != SPRITE_TILE_GRASS && t != SPRITE_TILE_DIRT && t != SPRITE_TILE_WATER)
                continue;
 
            map_change_tile(nr, nc, SPRITE_TILE_LAVA, TILE_FLAG_DAMAGE);
            lava_cells[lava_count].row = (short)nr;
            lava_cells[lava_count].col = (short)nc;
            lava_count++;
            queue_nearby_tree_burns(nr, nc);
            break;
        }
    }
 
    /* Deco tick: burn one tree per tick */
    evo_deco_timer++;
    if (evo_deco_timer >= EVO_DECO_INTERVAL) {
        evo_deco_timer = 0;
 
        for (int q = 0; q < burn_queue_count; q++) {
            burn_queue[q].burn_delay -= EVO_DECO_INTERVAL;
            if (burn_queue[q].burn_delay <= 0) {
                int idx = burn_queue[q].deco_idx;
                int target = deco_burn_target(decorations[idx].type);
                if(target != -1){
                    deco_change_type(idx, target);
                }
                burn_queue[q] = burn_queue[--burn_queue_count];
                break; //once tree per tick
            }
        }
    }
}

/* Beach map evolution*/

//right now using sand as a place holder because i dont have a ice tile yet
 
#define ICE_MAX 80
typedef struct { 
    short row, col; 
} IceCell;

IceCell ice_cells[ICE_MAX];
int     ice_count = 0;

#define FREEZE_QUEUE_MAX 20

typedef struct{
    int deco_idx;
    int freeze_delay;
} FreezeEntry;

FreezeEntry freeze_queue[FREEZE_QUEUE_MAX];
int freeze_queue_count = 0;

/* Pick seed points: water tiles that are next to a sand tile.
(this is to make it more realistic cuz ice forms on coastlines)*/

void beach_seed_ice(void) {
    int seeds = 2 + rand() % 3;   /* 2-4 seeds */
    for (int s = 0; s < seeds && ice_count < ICE_MAX; s++) {
        for (int attempt = 0; attempt < 400; attempt++) {
            int r = 1 + rand() % (MAP_HEIGHT - 2);
            int c = 1 + rand() % (MAP_WIDTH  - 2);
            if (map_get_tile(r, c) != SPRITE_TILE_WATER) continue;
 
            /* Must be touching sand */
            int near_sand = 0;
            if (r > 0            && map_get_tile(r-1, c) == SPRITE_TILE_SAND) near_sand = 1;
            if (r < MAP_HEIGHT-1 && map_get_tile(r+1, c) == SPRITE_TILE_SAND) near_sand = 1;
            if (c > 0            && map_get_tile(r, c-1) == SPRITE_TILE_SAND) near_sand = 1;
            if (c < MAP_WIDTH-1  && map_get_tile(r, c+1) == SPRITE_TILE_SAND) near_sand = 1;
            if (!near_sand) continue;
 
            map_change_tile(r, c, SPRITE_TILE_ICE, TILE_FLAG_ICE);
            ice_cells[ice_count].row = (short)r;
            ice_cells[ice_count].col = (short)c;
            ice_count++;
            break;
        }
    }
}

void beach_queue_nearby_tree_freeze(int ice_row, int ice_col){
    for(int i = 0; i < deco_count; i++){
        if(deco_ice_target(decorations[i].type) == -1) continue;

         int already = 0;
        for (int q = 0; q < freeze_queue_count; q++)
            if (freeze_queue[q].deco_idx == i) { already = 1; break; }
        if (already) continue;
        
        int dtype = decorations[i].type;
        int deco_col = (decorations[i].x + DECO_LOOKUP[dtype].w / 2) >> 4;
        int deco_row = (decorations[i].y + DECO_LOOKUP[dtype].h - 1) >> 4;

        int dist_r   = deco_row - ice_row; 
        if (dist_r < 0) 
            dist_r = -dist_r;

        int dist_c   = deco_col - ice_col; 
        if (dist_c < 0) 
            dist_c = -dist_c;

        if (dist_r > 2 || dist_c > 2) continue;
 
        if (freeze_queue_count >= FREEZE_QUEUE_MAX) return;
        freeze_queue[freeze_queue_count].deco_idx   = i;
        freeze_queue[freeze_queue_count].freeze_delay = 180 + rand() % 300;
        freeze_queue_count++;
    }
}
 
void beach_update(void) {
    if (ice_count == 0) return;   /* nothing seeded yet â€” safety guard */
 
    evo_tile_timer++;
    if (evo_tile_timer >= EVO_TILE_INTERVAL && ice_count < ICE_MAX){
         evo_tile_timer = 0;
 
        /* Pick a random existing ice cell to spread from */
        int src = rand() % ice_count;
        int sr  = ice_cells[src].row;
        int sc  = ice_cells[src].col;
    
        //Shuffled neighbour order
        int dr[4] = {-1,  1,  0,  0};
        int dc[4] = { 0,  0, -1,  1};

        for (int i = 3; i > 0; i--) {
            int j   = rand() % (i + 1);
            int tmp;

            tmp = dr[i];
            dr[i] = dr[j]; 
            dr[j] = tmp;

            tmp = dc[i]; 
            dc[i] = dc[j]; 
            dc[j] = tmp;
        }
    
        for (int d = 0; d < 4; d++) {
            int nr = sr + dr[d];
            int nc = sc + dc[d];
            /* Ice spreads only into water â€” not over sand/stone/grass */
            if (map_get_tile(nr, nc) != SPRITE_TILE_WATER) continue;
    
            map_change_tile(nr, nc, SPRITE_TILE_ICE, TILE_FLAG_ICE);
            ice_cells[ice_count].row = (short)nr;
            ice_cells[ice_count].col = (short)nc;
            ice_count++;
            beach_queue_nearby_tree_freeze(nr, nc);
            break;
        }
    }
   
    /* Deco Tick: freeze one tree per tick */
    evo_deco_timer++;
    if (evo_deco_timer >= EVO_DECO_INTERVAL) {
        evo_deco_timer = 0;
 
        for (int q = 0; q < freeze_queue_count; q++) {
            freeze_queue[q].freeze_delay -= EVO_DECO_INTERVAL;
            if (freeze_queue[q].freeze_delay <= 0) {
                int idx = freeze_queue[q].deco_idx;
                int target = deco_ice_target(decorations[idx].type);
                if(target != -1){
                    deco_change_type(idx, target);
                }
                freeze_queue[q] = freeze_queue[--freeze_queue_count];
                break; //once tree per tick
            }
        }
    }
}
 
/* Call this from map_evolution_init for the beach map: */
void beach_init(void) {
    ice_count = 0;
    /* Delay: ice starts forming after ~20 s */
    evo_tile_timer = -(1200 - EVO_TILE_INTERVAL);
    beach_seed_ice();
}

/* Ice map evolution*/
//isolated lava vents appear and melt surrounding ice after a timer

#define ICE_LAVA_MAX     12   /* max simultaneous active vents */
#define ICE_VENT_INTERVAL (EVO_TILE_INTERVAL * 3)  /* new vent every ~4.5 s */
 
/* How long a vent stays active before cooling: 8-18 seconds */
#define ICE_MELT_DELAY_MIN  480
#define ICE_MELT_DELAY_MAX 1080
 
typedef struct {
    short row, col;
    int   melt_timer;   /* frames remaining until this vent cools */
} IceLavaCell;
 
IceLavaCell ice_lava_cells[ICE_LAVA_MAX];
int ice_lava_count = 0;
 
void ice_burn_adjacent_trees(int lava_row, int lava_col){
    for (int i = 0; i < deco_count; i++) {
        int target = deco_burn_target(decorations[i].type);
        if (target == -1) continue;
 
        int dtype = decorations[i].type;
        int deco_col = (decorations[i].x + DECO_LOOKUP[dtype].w / 2) >> 4;
        int deco_row = (decorations[i].y + DECO_LOOKUP[dtype].h - 1) >> 4;

        int dist_r = deco_row - lava_row; 
        if (dist_r < 0){
            dist_r = -dist_r;
        }

        int dist_c = deco_col - lava_col; 
        if (dist_c < 0){
            dist_c = -dist_c;
        }

        if (dist_r > 1 || dist_c > 1) continue; /* only directly adjacent */
 
        deco_change_type(i, target);
    }
}


/* Spawn one new vent on a random ice tile, far enough from existing vents */
void ice_spawn_vent(void) {
    for (int attempt = 0; attempt < 120; attempt++) {
        int r = 1 + rand() % (MAP_HEIGHT - 2);
        int c = 1 + rand() % (MAP_WIDTH  - 2);
 
        if (map_get_tile(r, c) != SPRITE_TILE_SNOW) continue;
 
        /* Enforce a minimum gap of 2 tiles between vents */
        int too_close = 0;
        for (int q = 0; q < ice_lava_count; q++) {
            int dr = r - ice_lava_cells[q].row; 
            if (dr < 0){
                dr = -dr;
            }

            int dc = c - ice_lava_cells[q].col; 
            if (dc < 0){
                dc = -dc;
            }

            if (dr <= 2 && dc <= 2) { 
                too_close = 1; break; 
            }
        }
        if (too_close) continue;
 
        map_change_tile(r, c, SPRITE_TILE_LAVA, TILE_FLAG_DAMAGE);
        ice_lava_cells[ice_lava_count].row = (short)r;
        ice_lava_cells[ice_lava_count].col = (short)c;
        ice_lava_cells[ice_lava_count].melt_timer = ICE_MELT_DELAY_MIN + rand() % (ICE_MELT_DELAY_MAX - ICE_MELT_DELAY_MIN);
        ice_lava_count++;
        ice_burn_adjacent_trees(r, c);
        return;
    }
    // If no valid spot found this tick, just wait for the next interval
}
 
void ice_map_update(void) {
    /* Tile tick: maybe spawn a new vent*/
    evo_tile_timer++;
    if (evo_tile_timer >= ICE_VENT_INTERVAL) {
        evo_tile_timer = 0;
        if (ice_lava_count < ICE_LAVA_MAX)
            ice_spawn_vent();
    }
 
    // Cooldown tick: advance every vent's timer by 1 frame */
    int new_count = 0;
    for (int q = 0; q < ice_lava_count; q++) {
        ice_lava_cells[q].melt_timer--;
 
        if (ice_lava_cells[q].melt_timer <= 0) {
            // Vent cools: lava â†’ scorched dirt
            int lr = ice_lava_cells[q].row;
            int lc = ice_lava_cells[q].col;
            map_change_tile(lr, lc, SPRITE_TILE_DIRT, 0);
 
            // Melt orthogonal ice neighbours â†’ warm water 
            const int dr[4] = {-1,  1,  0,  0};
            const int dc[4] = { 0,  0, -1,  1};
            for (int d = 0; d < 4; d++) {
                int nr = lr + dr[d];
                int nc = lc + dc[d];
                if (map_get_tile(nr, nc) == SPRITE_TILE_SNOW)
                    map_change_tile(nr, nc, SPRITE_TILE_WATER_BRIGHT, TILE_FLAG_SLOW);
            }
            // Entry expires â€” don't carry it forward 
        } else {
            ice_lava_cells[new_count++] = ice_lava_cells[q];
        }
    }
    ice_lava_count = new_count;
}
 
/* Call this from map_evolution_init for the ice map: */
void ice_map_init(void) {
    ice_lava_count = 0;
    /* First vent appears after ~10 s */
    evo_tile_timer = -(600 - ICE_VENT_INTERVAL);
}
 
// Rocky Map Evolution
//rings of land flood inward over time
#define ROCKY_MAX_FLOOD_RINGS  4
#define ROCKY_FLOOD_INTERVAL  1800   /* flood one ring every 30 s */
 
int rocky_flood_ring  = 0;
int rocky_flood_timer = 0;
 
void rocky_flood_ring_tiles(int ring) {
    /* Top and bottom rows of this ring */
    for (int c = ring; c < MAP_WIDTH - ring; c++) {
        SpriteID t;
        t = map_get_tile(ring, c);
        if (t != SPRITE_TILE_WATER && t != SPRITE_TILE_STONE)
            map_change_tile(ring, c, SPRITE_TILE_WATER, TILE_FLAG_SLOW);
 
        t = map_get_tile(MAP_HEIGHT - 1 - ring, c);
        if (t != SPRITE_TILE_WATER && t != SPRITE_TILE_STONE)
            map_change_tile(MAP_HEIGHT - 1 - ring, c, SPRITE_TILE_WATER, TILE_FLAG_SLOW);
    }
    /* Left and right columns (skip corners already done above) */
    for (int r = ring + 1; r < MAP_HEIGHT - 1 - ring; r++) {
        SpriteID t;
        t = map_get_tile(r, ring);
        if (t != SPRITE_TILE_WATER && t != SPRITE_TILE_STONE)
            map_change_tile(r, ring, SPRITE_TILE_WATER, TILE_FLAG_SLOW);
 
        t = map_get_tile(r, MAP_WIDTH - 1 - ring);
        if (t != SPRITE_TILE_WATER && t != SPRITE_TILE_STONE)
            map_change_tile(r, MAP_WIDTH - 1 - ring, SPRITE_TILE_WATER, TILE_FLAG_SLOW);
    }
}
 
void rocky_update(void) {
    rocky_flood_timer++;
    if (rocky_flood_timer >= ROCKY_FLOOD_INTERVAL &&
        rocky_flood_ring  <  ROCKY_MAX_FLOOD_RINGS) {
        rocky_flood_timer = 0;
        rocky_flood_ring_tiles(rocky_flood_ring);
        rocky_flood_ring++;
    }
}
 
 
void map_evolution_init(int map_index) {
    /* Reset all state */
    evo_tile_timer    = 0;
    evo_deco_timer    = 0;
    tile_redraw_count = 0;
    deco_redraw_count = 0;
 
    lava_count        = 0;
    burn_queue_count  = 0;
    ice_count         = 0;
    ice_lava_count    = 0;
    rocky_flood_ring  = 0;
    rocky_flood_timer = 0;
 
    switch (map_index) {
        case 1:
            current_map_evo = MAP_EVO_WETLAND;
            /* Pre-load a negative timer offset so lava starts ~30 s in */
            evo_tile_timer  = -(1800 - EVO_TILE_INTERVAL);
            wetland_seed_lava();
            break;
        case 2:
            current_map_evo = MAP_EVO_BEACH;
            beach_init();
            break;
        /* Add cases 3 (ICE) and 4 (BEACH) when those maps are built */
        case 3:
            current_map_evo = MAP_EVO_ICE;
            ice_map_init();
            break;
        case 4:
            current_map_evo = MAP_EVO_ROCKY;
            rocky_flood_timer = -1800;   /* first flood 30 s after start */
            break;
        default:
            current_map_evo = MAP_EVO_NONE;
            break;
    }
}
 
void map_evolution_update(void) {
    switch (current_map_evo) {
        case MAP_EVO_WETLAND: wetland_update();  break;
        case MAP_EVO_BEACH:   beach_update();    break;
        case MAP_EVO_ICE:     ice_map_update();  break;
        case MAP_EVO_ROCKY:   rocky_update();    break;
        default: break;
    }
}


/* ===========================================================================
 * src/game/entity.c
 * =========================================================================*/
/* #include "entity.h" -- merged */
/* #include "player.h" -- merged */
/* #include "sprite.h" -- merged */
/* #include "renderer.h" -- merged */
/* #include "decorations.h" -- merged */
/* #include "projectile.h" -- merged */

Entity entities[MAX_ENTITIES];

Entity* spawn_entity(EntityType type){
    for(int i = 0; i < MAX_ENTITIES; i++){
        if(!entities[i].active){
            entities[i].is_ai = 0;
            entities[i].active = 1;
            entities[i].type = type;
            entities[i].player_cfg = NULL; //since not player, if player use player_init
            entities[i].anim_def = NULL;
            entities[i].dying = 0;
            entities[i].was_hit = 0;
            entities[i].damage = 0;
            entities[i].attack_s1 = 0;
            entities[i].attack_s2 = 0;
            entities[i].attack_p = 0;
            entities[i].pending_erase_b1 = 0;
            entities[i].pending_erase_b2 = 0;
            entities[i].shoot_cooldown = 0;
            entities[i].arrow_fired = 0;
            entities[i].owner = NULL;

            entities[i].atk1_cooldown = 0;
            entities[i].atk2_cooldown = 0;

            entities[i].blocking = 0;
            entities[i].block_cooldown = 0;
            entities[i].block_timer = 0;

            entities[i].dash_cooldown = 0;
            entities[i].dash_timer = 0;
            entities[i].is_dashing = 0;
            return &entities[i];
        }
    }
    return NULL;
}

void entity_update_all(int cur_buf){
    for(int i = 0; i < MAX_ENTITIES; i++){
        if (!entities[i].active)
            continue;
        switch(entities[i].type){
            case ENTITY_PLAYER:
                player_update(&entities[i], cur_buf);
                break;
            
            case ENTITY_ENEMY:
                enemy_update(&entities[i]);
                break;
            
            case ENTITY_PROJECTILE:
                projectile_update(&entities[i], cur_buf);
                break;
            default: 
                break;
        }
    }
}

void entity_draw_all()
{
    for(int i = 0; i < MAX_ENTITIES; i++)
    {
        if(entities[i].active)
            draw_entity(&entities[i]);
    }
}

void draw_entity(Entity *e){
    switch (e->type){
        case ENTITY_PLAYER: 
            player_draw(e);
            break;
        case ENTITY_ENEMY:
            enemy_draw(e);
            break;
        case ENTITY_PROJECTILE:
            projectile_draw(e);
            break;
        default:
            if (e->sprite_id >= 0)
                draw_sprite(&sprites[e->sprite_id], e->x, e->y, 0, 0);
            break;
    }
}

void entity_erase_all(int cur_buf){
    /* erase - restore tiles under every entity*/
    for (int i = 0; i < MAX_ENTITIES; i++){
        if (!entities[i].active){
            continue;
        }
        erase_sprite(entities[i].prev_x[cur_buf] - 4, entities[i].prev_y[cur_buf], entities[i].width + 4, entities[i].height);

        if(cur_buf == 0 && entities[i].pending_erase_b1){
            entities[i].pending_erase_b1 = 0;
        }

        if(cur_buf == 1 && entities[i].pending_erase_b2){
            entities[i].pending_erase_b2 = 0;
        }

        if(entities[i].pending_erase && !entities[i].pending_erase_b1 && !entities[i].pending_erase_b2){
            entities[i].pending_erase = 0;
            entities[i].active = 0;
        }
    }
}


